#include <stdio.h>
#include <string.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S[11], F[100005][11];
        int N;
        scanf("%s %d", S, &N);
        for (int i = 0; i < N; i++) {
            scanf("%s", F[i]);
        }
        int count = 0;
        for (int mask = 0; mask < (1 << N); mask++) {
            char temp[11] = {0};
            strcpy(temp, S);
            for (int i = 0; i < N; i++) {
                if ((mask & (1 << i)) != 0) {
                    for (int j = 0; j < 10; j++) {
                        if (F[i][j] == '+') {
                            temp[j] = (temp[j] == 'b') ? 'w' : 'b';
                        }
                    }
                }
            }
            int allBlack = 1;
            for (int i = 0; i < 10; i++) {
                if (temp[i] != 'b') {
                    allBlack = 0;
                    break;
                }
            }
            count = (count + allBlack) % MOD;
        }
        printf("%d\n", count);
    }
    return 0;
}

