        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String S = sc.next();
            int N = sc.nextInt();
            String[] F = new String[N];
            for (int i = 0; i < N; i++) {
                F[i] = sc.next();
            }
            int count = 0;
            for (int mask = 0; mask < (1 << N); mask++) {
                char[] temp = S.toCharArray();
                for (int i = 0; i < N; i++) {
                    if ((mask & (1 << i)) != 0) {
                        for (int j = 0; j < 10; j++) {
                            if (F[i].charAt(j) == '+') {
                                temp[j] = (temp[j] == 'b') ? 'w' : 'b';
                            }
                        }
                    }
                }
                int allBlack = 1;
                for (int i = 0; i < 10; i++) {
                    if (temp[i] != 'b') {
                        allBlack = 0;
                        break;
                    }
                }
                count = (count + allBlack) % 1000000007;
